/*
注意到最后的连边情况构成了一个森林，且森林中的每棵树的 A_i 之和为 0.
又注意到 N 很小，于是我们通过 Prim 预处理出所有节点集合构成一颗树的代价，
然后通过状压 dp 将若干个连通块拼起来统计.
时间复杂度为 O(2^nn^2+3^n).
*/
#include <bits/stdc++.h>
using namespace std;

const int N=16,INF=0x3f3f3f3f;

struct Edge{
    int to,val;
};

int n,m,a[N],g[1<<N],f[1<<N],dis[N];
vector<Edge> e[N];
bool b[N];

int Prim(int s,int st){
    memset(dis,0x3f,sizeof(dis));
    memset(b,0,sizeof(b));
    dis[st]=0;
    int sz=0,tmp=s,res=0;
    while(tmp)
        sz++,tmp-=(tmp&(-tmp));
    //计算 |s|，即集合 s 的大小
    while(sz--){
        int x=-1;
        for(int i=0;i<n;i++)
            if(((s>>i)&1) && !b[i] && (x==-1 || dis[i]<dis[x]) && dis[i]<INF)
                x=i;
        if(x==-1)
            return INF; // 集合不连通，返回 INF
        res+=dis[x],b[x]=1;
        for(Edge y:e[x])
            if(!b[y.to] && ((s>>y.to)&1) && dis[y.to]>y.val)
                dis[y.to]=y.val;
    }
    return res;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=0;i<n;i++)
        scanf("%d",&a[i]);
    for(int i=1,u,v,w;i<=m;i++){
        scanf("%d%d%d",&u,&v,&w);
        e[u].push_back({v,w});
        e[v].push_back({u,w});
    }
    for(int i=1;i<1<<n;i++){
        int sum=0,st;
        for(int j=0;j<n;j++)
            if((i>>j)&1)
                sum+=a[j],st=j;
        if(sum)
            g[i]=INF; // 不合法直接设为 INF
        else
            g[i]=Prim(i,st); // 否则在集合 i 中，以 st 为起点作 Prim 计算最小生成树的代价和
    }
    memset(f,0x3f,sizeof(f));
    f[0]=0;
    for(int i=1;i<1<<n;i++)
        for(int j=i;j;j=((j-1)&i))
            f[i]=min(f[i],f[i^j]+g[j]);
    if(f[(1<<n)-1]==INF)
        printf("Impossible");
    else
        printf("%d",f[(1<<n)-1]);
    return 0;
}
